protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name so existing documents
        // and direct SQL queries referencing c.Discriminator continue to work.
        // EF Core 9 defaults to "$type".
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123") so existing
        // documents remain accessible via FindAsync and point-reads.
        // EF Core 9 defaults to key-only ids ("123").
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex removed — Cosmos DB provider now throws at startup.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep).
}

